    # Build subject‑level clauses, merging multiple predicates per subject
    subject_clauses: list[str] = []
    for s, pairs in subj_map.items():
        parts = [_phrase(s, p, o) for p, o in pairs]
        if len(parts) == 1:
            subject_clauses.append(parts[0])
        else:
            merged = ", ".join(parts[:-1]) + ", and " + parts[-1]
            subject_clauses.append(merged)

    # Try to connect related subjects using relative clauses
    # Check if any object in one clause matches a subject in another
    connected_clauses = []
    remaining_clauses = subject_clauses.copy()

    if len(remaining_clauses) > 1:
        # Try to find connections between subjects and objects
        i = 0
        while i < len(remaining_clauses):
            current_clause = remaining_clauses[i]
            connected = False

            # Try to find other clauses that can be connected with relative clauses
            for j in range(i + 1, len(remaining_clauses)):
                other_clause = remaining_clauses[j]
                # Extract potential subject from current clause (first word before space/comma)
                import re
                current_subject_match = re.search(r'^([A-Z][^,]+)', current_clause)
                if current_subject_match:
                    current_subject = current_subject_match.group(1).strip()
                    # Check if current subject appears in other clause's object position
                    if current_subject in other_clause:
                        # Connect with relative clause
                        # Remove "is" from other_clause to make it a relative clause
                        other_reduced = re.sub(r' is ', ', which is ', other_clause, count=1)
                        other_reduced = re.sub(r' has ', ', which has ', other_reduced, count=1)
                        other_reduced = re.sub(r' serves ', ', which serves ', other_reduced, count=1)
                        other_reduced = re.sub(r' operates ', ', which operates ', other_reduced, count=1)

                        # Try to make it flow better
                        if ', which is' in other_reduced or ', which has' in other_reduced:
                            connected_clauses.append(current_clause + other_reduced[len(current_clause):])
                            remaining_clauses.pop(j)
                            connected = True
                            break

            if not connected:
                connected_clauses.append(current_clause)
            i += 1

        remaining_clauses = connected_clauses

    # Combine all clauses into one sentence
    if len(remaining_clauses) == 1:
        sentence = remaining_clauses[0] + "."
    else:
        sentence = ", ".join(remaining_clauses[:-1]) + ", and " + remaining_clauses[-1] + "."

    # Capitalise first character
    return sentence[0].upper() + sentence[1:]

